import { readFile, writeFile } from 'node:fs/promises';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const repoRoot = resolve(__dirname, '..');

const runtimeSourceFiles = [
  'src/runtime/config.js',
  'src/runtime/url-utils.js',
  'src/runtime/cache.js',
  'src/runtime/adapters/webgl.js',
  'src/runtime/adapters/webgpu.js',
  'src/runtime/engine.js',
  'src/runtime/dom.js',
  'src/runtime/queue.js',
  'src/runtime/orchestrator.js'
];

const outputFile = 'src/runtime/runtime.bundle.js';
const shouldCheck = process.argv.includes('--check');

async function composeBundleContent() {
  const parts = [];
  for (const relativePath of runtimeSourceFiles) {
    const absolutePath = resolve(repoRoot, relativePath);
    const content = await readFile(absolutePath, 'utf8');
    parts.push(`// --- BEGIN ${relativePath} ---\n${content.trimEnd()}\n// --- END ${relativePath} ---\n`);
  }

  const banner = `// AUTO-GENERATED FILE - DO NOT EDIT DIRECTLY\n// Generated by tools/build-runtime-bundle.mjs\n\n`;
  return banner + parts.join('\n');
}

async function check() {
  const expected = await composeBundleContent();
  let current = '';

  try {
    current = await readFile(resolve(repoRoot, outputFile), 'utf8');
  } catch {
    process.stderr.write(`${outputFile} does not exist. Run node tools/build-runtime-bundle.mjs\n`);
    process.exitCode = 1;
    return;
  }

  if (current !== expected) {
    process.stderr.write(`Runtime bundle is out of date. Run node tools/build-runtime-bundle.mjs\n`);
    process.exitCode = 1;
    return;
  }

  process.stdout.write(`Runtime bundle is up to date (${outputFile}).\n`);
}

async function build() {
  const output = await composeBundleContent();
  await writeFile(resolve(repoRoot, outputFile), output, 'utf8');

  process.stdout.write(`Built ${outputFile} from ${runtimeSourceFiles.length} source files.\n`);
}

const task = shouldCheck ? check : build;

task().catch((error) => {
  process.stderr.write(`Failed to build runtime bundle: ${String(error)}\n`);
  process.exitCode = 1;
});
